// Program: Find maximum of two numbers
BEGIN
    INPUT a, b
    IF a > b THEN
        max = a
    ELSE
        max = b
    ENDIF
    OUTPUT max
END

// CFG Analysis:
// Node 1: Entry
// Node 2: Decision (a > b)
// Node 3: Assignment (max = a)
// Node 4: Assignment (max = b)
// Node 5: Output
// Node 6: Exit
//
// Edges: 2→3 (TRUE), 2→4 (FALSE), 3→5, 4→5, 5→6
// Total Edges = 5, Nodes = 6
// V(G) = E - N + 2 = 5 - 6 + 2 = 1
// OR: 1 decision point + 1 = 2 - wait... 
// Actually: 1 decision = 1+1 = 2? No - 
// Let me recalculate: The program has ONE if statement
// So cyclomatic complexity = 1 + 1 = 2
// Using E-N+2: E=5, N=6, so 5-6+2 = 1? There's a discrepancy
// Note: The entry and exit nodes might be counted differently

#include <stdio.h>

int findSum(int n) {
    int sum = 0;
    // Decision point 1: while loop
    while (n > 0) {
        // Decision point 2: for loop
        for (int i = 1; i <= n; i++) {
            sum += i;
        }
        n--;
    }
    return sum;
}

/*
 * CFG Analysis:
 * Node 1: Entry
 * Node 2: Decision (n > 0) - Decision Point 1
 * Node 3: Decision (i <= n) - Decision Point 2
 * Node 4: sum += i
 * Node 5: n--
 * Node 6: Return
 * Node 7: Exit
 * 
 * Edges: 2→3(T), 2→7(F), 3→4(T), 3→5(F), 4→3, 5→2
 * Total E = 6, N = 7
 * V(G) = E - N + 2 = 6 - 7 + 2 = 1
 * 
 * Using decision point formula:
 * Decision points = 2 (while + for)
 * V(G) = 2 + 1 = 3
 * 
 * 3 independent paths must be tested
 */

int main() {
    int result = findSum(5);
    printf("Sum: %d\n", result);
    return 0;
}
